// ── Lite config: edit these values ──
const config = {
  brandName: 'YourBrand',
  wpUrl: 'https://yourdomain.com',
  seedKeywords: ['your main keyword', 'second keyword', 'third keyword'],
  competitors: ['competitor1.com', 'competitor2.com', 'competitor3.com']
};
return [{ json: config }];

// Build prompt set for each engine
const client = $input.first().json;
const keywords = (client.seedKeywords || []).slice(0, 5); // limit to 5 for daily run
const competitors = client.competitors || [];

const promptTemplates = [
  // Brand-mention detection
  `Who are the best {$kw} providers in 2025? List your top 5 with reasons.`,
  `Compare the top {$kw} tools. Which would you recommend for a mid-size company?`,
  `What are the pros and cons of {$brand} for {$kw}?`,
  // Citation-worthy content
  `What is {$kw}? Explain with examples and best practices.`,
  `How to choose the right {$kw} solution? List evaluation criteria.`
];

const items = [];
keywords.forEach(kw => {
  promptTemplates.forEach((tmpl, i) => {
    const prompt = tmpl.replace('{\$kw}', kw).replace('{\$brand}', client.brandName);
    items.push({
      json: {
        ...client,
        keyword: kw,
        promptId: `${kw.replace(/\s/g, '_')}_${i}`,
        prompt,
        competitors
      }
    });
  });
});
return items;

// Analyze each response for brand mentions, citations, links
const items = $input.all();
const results = [];

items.forEach(item => {
  const json = item.json;
  const brand = (json.brandName || '').toLowerCase();
  const competitors = json.competitors || [];

  let responseText = '';
  let engine = '';
  let citations = [];

  // Normalize response from each engine
  if (json.message?.content) {
    responseText = typeof json.message.content === 'string' ? json.message.content : JSON.stringify(json.message.content);
    engine = json.engine || 'chatgpt';
  } else if (json.choices?.[0]?.message?.content) {
    responseText = json.choices[0].message.content;
    engine = 'perplexity';
    if (json.citations) citations = json.citations;
  } else if (json.content) {
    responseText = json.content;
    engine = 'gemini';
  }

  const lowerResp = responseText.toLowerCase();

  // Check brand mention
  const brandMentioned = lowerResp.includes(brand);
  const brandMentionCount = (lowerResp.match(new RegExp(brand, 'g')) || []).length;

  // Check competitor mentions
  const compMentions = competitors.map(c => ({
    competitor: c,
    mentioned: lowerResp.includes(c.toLowerCase().split('.')[0]),
    count: (lowerResp.match(new RegExp(c.toLowerCase().split('.')[0], 'g')) || []).length
  }));

  // Citation score: 0-100
  const citationScore = Math.min(100, (brandMentionCount * 25) + (citations.length > 0 ? 20 : 0));

  // Position rank (1 = mentioned first)
  let brandPosition = 0;
  if (brandMentioned) {
    const brandIdx = lowerResp.indexOf(brand);
    const allMentions = [{name: brand, idx: brandIdx}, ...compMentions.filter(c => c.mentioned).map(c => ({name: c.competitor, idx: lowerResp.indexOf(c.competitor.toLowerCase().split('.')[0])}))];
    allMentions.sort((a, b) => a.idx - b.idx);
    brandPosition = allMentions.findIndex(m => m.name === brand) + 1;
  }

  results.push({
    json: {
      ...json,
      engine,
      responseText: responseText.slice(0, 2000),
      citations,
      brandMentioned,
      brandMentionCount,
      brandPosition,
      compMentions,
      citationScore,
      analyzedAt: new Date().toISOString()
    }
  });
});

return results;

